//! Guarded, append-only recovery of claims stranded by legacy identity changes.

use mindleak_session::compatible_legacy_owner;
use rusqlite::{params, Transaction, TransactionBehavior};

use crate::error::{LodestarError, Result};

use super::coordination::PARKING_GRACE_SECS;
use super::{ClaimTransfer, LodestarStore};

impl LodestarStore {
    pub fn recover_claim(
        &self,
        task_id: &str,
        expected_owner: &str,
        target_agent: &str,
        reason: &str,
        lease_secs: i64,
        now: i64,
    ) -> Result<bool> {
        if reason.trim().is_empty() {
            return Err(LodestarError::Invalid(
                "claim recovery requires a reason".to_string(),
            ));
        }
        if !compatible_legacy_owner(expected_owner, target_agent) {
            return Err(LodestarError::Invalid(
                "claim recovery requires a compatible legacy owner and registered session identity"
                    .to_string(),
            ));
        }
        let transaction = Transaction::new_unchecked(&self.conn, TransactionBehavior::Immediate)?;
        let prior = load_prior_claim(&transaction, task_id)?;
        if prior.owner != expected_owner {
            return Err(LodestarError::Invalid(format!(
                "task owner changed concurrently: expected {expected_owner}, found {}",
                prior.owner
            )));
        }
        let reclaimable = match prior.status.as_str() {
            "claimed" => prior.lease_expires_at.is_some_and(|expiry| expiry < now),
            "needs_input" | "paused" => prior
                .parked_at
                .is_some_and(|parked| parked + PARKING_GRACE_SECS < now),
            _ => false,
        };
        if !reclaimable {
            return Err(LodestarError::Invalid(
                "claim recovery is allowed only after the live lease or parking grace expires"
                    .to_string(),
            ));
        }
        let changed = transaction.execute(
            "UPDATE tasks
             SET status = 'claimed', owner = ?3, claim_started_at = ?4,
                 lease_expires_at = ?5, parked_at = NULL, updated_at = ?4
             WHERE id = ?1 AND owner = ?2 AND status = ?6",
            params![
                task_id,
                expected_owner,
                target_agent,
                now,
                now + lease_secs.max(1),
                prior.status
            ],
        )?;
        if changed != 1 {
            return Ok(false);
        }
        transaction.execute(
            "INSERT INTO task_claim_transfers
                 (task_id, from_owner, to_owner, recovered_by, reason, from_status,
                  from_claim_started_at, from_lease_expires_at, from_parked_at,
                  to_claim_started_at, transferred_at)
             VALUES (?1, ?2, ?3, ?3, ?4, ?5, ?6, ?7, ?8, ?9, ?9)",
            params![
                task_id,
                prior.owner,
                target_agent,
                reason.trim(),
                prior.status,
                prior.claim_started_at,
                prior.lease_expires_at,
                prior.parked_at,
                now
            ],
        )?;
        transaction.commit()?;
        Ok(true)
    }

    pub fn claim_transfer_history(&self, task_id: &str) -> Result<Vec<ClaimTransfer>> {
        let mut statement = self.conn.prepare(
            "SELECT id, task_id, from_owner, to_owner, recovered_by, reason,
                    from_status, from_claim_started_at, from_lease_expires_at,
                    from_parked_at, to_claim_started_at, transferred_at
             FROM task_claim_transfers WHERE task_id = ?1 ORDER BY id ASC",
        )?;
        let rows = statement.query_map(params![task_id], |row| {
            Ok(ClaimTransfer {
                id: row.get(0)?,
                task_id: row.get(1)?,
                from_owner: row.get(2)?,
                to_owner: row.get(3)?,
                recovered_by: row.get(4)?,
                reason: row.get(5)?,
                from_status: row.get(6)?,
                from_claim_started_at: row.get(7)?,
                from_lease_expires_at: row.get(8)?,
                from_parked_at: row.get(9)?,
                to_claim_started_at: row.get(10)?,
                transferred_at: row.get(11)?,
            })
        })?;
        rows.collect::<std::result::Result<Vec<_>, _>>()
            .map_err(Into::into)
    }
}

struct PriorClaim {
    owner: String,
    status: String,
    claim_started_at: Option<i64>,
    lease_expires_at: Option<i64>,
    parked_at: Option<i64>,
}

fn load_prior_claim(transaction: &Transaction<'_>, task_id: &str) -> Result<PriorClaim> {
    transaction
        .query_row(
            "SELECT owner, status, claim_started_at, lease_expires_at, parked_at
             FROM tasks WHERE id = ?1 AND owner IS NOT NULL",
            params![task_id],
            |row| {
                Ok(PriorClaim {
                    owner: row.get(0)?,
                    status: row.get(1)?,
                    claim_started_at: row.get(2)?,
                    lease_expires_at: row.get(3)?,
                    parked_at: row.get(4)?,
                })
            },
        )
        .map_err(|error| match error {
            rusqlite::Error::QueryReturnedNoRows => LodestarError::NotFound(task_id.to_string()),
            other => other.into(),
        })
}

#[cfg(test)]
mod tests {
    use mindleak_session::SessionRegistry;

    use super::*;
    use crate::model::TaskScope;
    use crate::store::test_support::{goal, store, NOW};

    const SESSION_A: &str = "00112233445566778899aabbccddeeff";
    const SESSION_B: &str = "ffeeddccbbaa99887766554433221100";

    fn session(token: &str) -> String {
        SessionRegistry::new("copilot")
            .unwrap()
            .open_session(token)
            .unwrap()
            .agent_id
    }

    #[test]
    fn expired_legacy_claim_recovers_with_scope_and_append_only_audit() {
        let store = store();
        let task = store
            .create_task(&goal(&store).id, "Recover", "done", None, NOW)
            .unwrap();
        let scope = TaskScope {
            paths: vec!["src/**".into()],
            symbols: vec!["symbol:src/lib.rs:run".into()],
        };
        assert!(store
            .claim_task_with_scope(&task.id, "copilot-abcd1234", 10, &scope, NOW)
            .unwrap());
        let target = session(SESSION_A);
        assert!(!store.claim_task(&task.id, &target, 60, NOW + 11).unwrap());
        assert!(store
            .recover_claim(
                &task.id,
                "copilot-abcd1234",
                &target,
                "server identity changed",
                60,
                NOW + 11,
            )
            .unwrap());

        let recovered = store.get_task(&task.id).unwrap().unwrap();
        assert_eq!(recovered.owner.as_deref(), Some(target.as_str()));
        assert_eq!(recovered.claim_started_at, Some(NOW + 11));
        assert_eq!(store.task_scope(&task.id).unwrap(), scope);
        let history = store.claim_transfer_history(&task.id).unwrap();
        assert_eq!(history.len(), 1);
        assert_eq!(history[0].from_owner, "copilot-abcd1234");
        assert_eq!(history[0].to_owner, target);
        assert_eq!(history[0].from_claim_started_at, Some(NOW));
        assert_eq!(history[0].from_lease_expires_at, Some(NOW + 10));
    }

    #[test]
    fn live_wrong_base_and_qualified_sibling_recoveries_are_rejected() {
        let store = store();
        let objective = goal(&store);
        let live = store
            .create_task(&objective.id, "Live", "done", None, NOW)
            .unwrap();
        assert!(store.claim_task(&live.id, "copilot", 60, NOW).unwrap());
        let target = session(SESSION_A);
        assert!(store
            .recover_claim(&live.id, "copilot", &target, "too early", 60, NOW + 1)
            .is_err());
        assert!(store
            .recover_claim(&live.id, "copilot", &target, "  ", 60, NOW + 61)
            .is_err());
        assert!(store
            .recover_claim(
                &live.id,
                "copilot",
                &SessionRegistry::new("claude")
                    .unwrap()
                    .open_session(SESSION_A)
                    .unwrap()
                    .agent_id,
                "wrong base",
                60,
                NOW + 61,
            )
            .is_err());

        let sibling = store
            .create_task(&objective.id, "Sibling", "done", None, NOW)
            .unwrap();
        assert!(store.claim_task(&sibling.id, &target, 10, NOW).unwrap());
        assert!(store
            .recover_claim(
                &sibling.id,
                &target,
                &session(SESSION_B),
                "session theft",
                60,
                NOW + 11,
            )
            .is_err());
        assert!(store
            .claim_transfer_history(&sibling.id)
            .unwrap()
            .is_empty());
    }

    #[test]
    fn parked_claim_waits_for_full_grace_before_recovery() {
        let store = store();
        let task = store
            .create_task(&goal(&store).id, "Parked", "done", None, NOW)
            .unwrap();
        assert!(store.claim_task(&task.id, "copilot", 60, NOW).unwrap());
        assert!(store.pause_task(&task.id, "copilot", NOW + 1).unwrap());
        let target = session(SESSION_A);
        assert!(store
            .recover_claim(
                &task.id,
                "copilot",
                &target,
                "before grace",
                60,
                NOW + 1 + PARKING_GRACE_SECS,
            )
            .is_err());
        assert!(store
            .recover_claim(
                &task.id,
                "copilot",
                &target,
                "owner disappeared",
                60,
                NOW + 2 + PARKING_GRACE_SECS,
            )
            .unwrap());
    }
}
